"use client"
import { useState } from 'react'
import QRCode from 'qrcode'

export default function QRCodeGenerator() {
  const [text, setText] = useState('')
  const [src, setSrc] = useState('')

  async function generate() {
    try {
      const url = await QRCode.toDataURL(text || ' ')
      setSrc(url)
    } catch (e) {
      console.error(e)
    }
  }

  function reset() {
    setText('')
    setSrc('')
  }

  return (
    <main className="container mx-auto p-4">
      <h1 className="text-2xl font-bold">QR Code Generator</h1>
      <div className="mt-4 max-w-md">
        <input value={text} onChange={e => setText(e.target.value)} className="w-full p-2 border rounded" placeholder="Text or URL" />
        <div className="flex gap-2 mt-3">
          <button onClick={generate} className="px-4 py-2 bg-blue-600 text-white rounded">Generate</button>
          <button onClick={reset} className="px-4 py-2 border rounded">Reset</button>
        </div>

        {src && (
          <div className="mt-4">
            <img src={src} alt="qr" />
            <div className="mt-2">
              <a href={src} download="qrcode.png" className="px-3 py-1 border rounded">Download</a>
            </div>
          </div>
        )}
      </div>
    </main>
  )
}
